const fs = require('fs');
const path = require('path');

// Configuration
const TYPES_PATH = path.resolve(__dirname, '../src/types/database.types.ts');
const OUTPUT_SCHEMA_PATH = path.resolve(__dirname, '../src/database/schema.ts');

const SCHEMA_HEADER = `/**
 * ⚠️ WARNING: DO NOT MANUALLY EDIT THIS FILE ⚠️
 * 
 * This file is AUTOMATICALLY GENERATED by \`npm run schema:generate\`.
 * Manual modifications will be lost.
 * 
 * Sources:
 * - src/types/database.types.ts (Supabase Schema)
 * - scripts/generate-watermelon-schema.js (Generator Logic)
 */

import { appSchema, tableSchema } from '@nozbe/watermelondb'

export default appSchema({
    version: 1, // INCREMENT_VERSION_HERE
    tables: [
`;

const SCHEMA_FOOTER = `    ],
})
`;

// Sync fields that must be on every table
const SYNC_FIELDS = [
    { name: 'created_at', type: 'number' },
    { name: 'updated_at', type: 'number' },
    { name: 'deleted_at', type: 'number' },
    { name: '_version', type: 'number' },
    { name: '_custom_sync_status', type: 'string', isOptional: true },
    { name: 'modified_by', type: 'string' }
];

// Fields to ignore from source (handled by sync fields or internal)
const IGNORE_FIELDS = [
    'id',
    'created_at',
    'updated_at',
    'deleted_at',
    'modified_by'
];

/**
 * Maps Supabase TS types to WatermelonDB schema types
 */
function mapType(tsType) {
    if (!tsType) return 'string';
    const cleanType = tsType.replace(/\| null/g, '').trim();

    if (cleanType === 'string') return 'string';
    if (cleanType === 'number') return 'number';
    if (cleanType === 'boolean') return 'boolean';
    if (cleanType === 'Json') return 'string'; // JSON stored as string
    if (cleanType.includes('[]')) return 'string'; // Arrays stored as JSON strings

    // Explicit overrides for known fields if needed
    if (cleanType === 'unknown') return 'string';

    return 'string'; // Default fallback
}

function extractBlock(content, openChar, closeChar, startIndex) {
    let openCount = 0;
    let block = '';
    let started = false;

    for (let i = startIndex; i < content.length; i++) {
        const char = content[i];
        if (char === openChar) {
            openCount++;
            started = true;
        } else if (char === closeChar) {
            openCount--;
        }

        if (started) {
            block += char;
            if (openCount === 0) return block;
        }
    }
    return '';
}

function parseSupabaseTypes(content) {
    const tables = {};

    // 1. Find Tables block
    const tablesStartIdx = content.indexOf('Tables: {');
    if (tablesStartIdx === -1) throw new Error("Could not find 'Tables' definition");

    // Extract the full Tables: { ... } block
    // Offset by 8 ("Tables: ".length) to point to the opening brace
    const tablesBlock = extractBlock(content, '{', '}', tablesStartIdx + 7);

    // 2. Iterate through each property inside Tables
    // Pattern: tableName: { Row: { ... } ... }
    const tableStartRegex = /(\w+):\s*\{\s*Row:\s*\{/g;
    let match;

    while ((match = tableStartRegex.exec(tablesBlock)) !== null) {
        const tableName = match[1];
        const tableStartIndex = match.index; // Start of "tableName:"

        // Find the full block for this table to restrict searching
        const tableDefStartBrace = tablesBlock.indexOf('{', tableStartIndex + tableName.length);
        const tableDefBlock = extractBlock(tablesBlock, '{', '}', tableDefStartBrace);

        // Inside Table Block: Find Row: { ... }
        const rowStartIdx = tableDefBlock.indexOf('Row: {');
        if (rowStartIdx === -1) continue;
        const rowOpenBrace = tableDefBlock.indexOf('{', rowStartIdx);
        const rowBlock = extractBlock(tableDefBlock, '{', '}', rowOpenBrace);

        // Inside Table Block: Find Relationships: [ ... ]
        let foreignKeys = new Set();
        const relStartIdx = tableDefBlock.indexOf('Relationships: [');
        if (relStartIdx !== -1) {
            const relOpenBrace = tableDefBlock.indexOf('[', relStartIdx);
            const relBlock = extractBlock(tableDefBlock, '[', ']', relOpenBrace);

            // Parse FKs from relationships
            const relRegex = /columns:\s*\["(\w+)"\]/g;
            let relMatch;
            while ((relMatch = relRegex.exec(relBlock)) !== null) {
                foreignKeys.add(relMatch[1]);
            }
        }

        // Parse Columns
        const columns = [];
        // Match "colName: type" lines
        // Cleanup the rowBlock first: remove outer braces
        const rowInner = rowBlock.substring(1, rowBlock.length - 1);
        const lines = rowInner.split('\n');

        lines.forEach(line => {
            const trimmed = line.trim();
            if (!trimmed) return;

            // Match "name: type" or "name?: type"
            const colMatch = trimmed.match(/^(\w+)(\??):\s*([^;]+)/);
            if (colMatch) {
                const name = colMatch[1];
                const rawType = colMatch[3];

                if (!IGNORE_FIELDS.includes(name)) {
                    columns.push({
                        name: name,
                        type: mapType(rawType),
                        // definition says string | null, usually
                        isOptional: rawType.includes('null') || colMatch[2] === '?',
                        isIndexed: foreignKeys.has(name) || name.endsWith('_id')
                    });
                }
            }
        });

        if (columns.length > 0) {
            tables[tableName] = columns;
        }
    }

    return tables;
}

function generateSchema() {
    console.log('🔄 Generating WatermelonDB Schema...');

    if (!fs.existsSync(TYPES_PATH)) {
        console.error(`❌ Types file not found: ${TYPES_PATH}`);
        console.error('   Run "npm run types:cloud-dev" to generate it first.');
        process.exit(1);
    }

    // 1. Read current schema (Logic moved to step 4)


    // 2. Parse Types
    const fileContent = fs.readFileSync(TYPES_PATH, 'utf8');
    const tables = parseSupabaseTypes(fileContent);

    // 3. Inject Local Infrastructure Tables (Not in Supabase Types)

    // SyncOutbox
    tables.sync_outbox = [
        { name: 'operation_id', type: 'string', isIndexed: true },
        { name: 'operation_type', type: 'string' },
        { name: 'table_name', type: 'string', isIndexed: true },
        { name: 'record_id', type: 'string', isIndexed: true },
        { name: 'payload', type: 'string' }, // JSON
        { name: 'version', type: 'number' },
        { name: 'lamport_clock', type: 'number' },
        { name: 'retry_count', type: 'number' },
        { name: 'status', type: 'string', isIndexed: true },
        { name: 'error_message', type: 'string', isOptional: true },
        { name: 'user_id', type: 'string', isOptional: true },
        { name: 'device_id', type: 'string', isOptional: true },
    ];

    // SyncState
    tables.sync_state = [
        { name: 'key', type: 'string', isIndexed: true },
        { name: 'value', type: 'string' }, // JSON
    ];

    // ProjectInvitation (Missing from backend types or local-only)
    tables.project_invitations = [
        { name: 'remote_id', type: 'string', isIndexed: true },
        { name: 'project_id', type: 'string', isIndexed: true },
        { name: 'inviter_id', type: 'string' },
        { name: 'invitee_email', type: 'string' },
        { name: 'invitee_id', type: 'string', isOptional: true },
        { name: 'role', type: 'string' },
        { name: 'status', type: 'string' },
        { name: 'expires_at', type: 'number' },
        { name: 'responded_at', type: 'number', isOptional: true },
    ];

    // ----------------------------------------------------    
    // Patch missing fields for reference tables (Models expect server_id but Supabase has id)
    // capture_methods, activity_sensitivity, sampling_designs use INT ID -> server_id (number)
    // ai_models uses UUID -> server_id (string)
    const refTablesNum = ['capture_methods', 'activity_sensitivity', 'sampling_designs'];
    refTablesNum.forEach(tableName => {
        if (tables[tableName]) {
            const existingNames = new Set(tables[tableName].map(c => c.name));
            if (!existingNames.has('server_id')) {
                tables[tableName].push({ name: 'server_id', type: 'number', isIndexed: true });
            }
        }
    });

    const refTablesStr = ['ai_models'];
    refTablesStr.forEach(tableName => {
        if (tables[tableName]) {
            const existingNames = new Set(tables[tableName].map(c => c.name));
            if (!existingNames.has('server_id')) {
                tables[tableName].push({ name: 'server_id', type: 'string', isIndexed: true });
            }
        }
    });

    // Patch missing fields for deployments (Model has fields not in Supabase types yet)
    if (tables.deployments) {
        const existingNames = new Set(tables.deployments.map(c => c.name));
        const missingFields = [
            { name: 'altitude', type: 'number', isOptional: true },
            { name: 'accuracy', type: 'number', isOptional: true },
            // Missing snapshot/FK fields
            { name: 'capture_method_id', type: 'number', isOptional: true, isIndexed: true },
            { name: 'activity_detection_sensitivity_id', type: 'number', isOptional: true, isIndexed: true },
            { name: 'timelapse_interval_seconds', type: 'number', isOptional: true },
            // Legacy/Model-only fields
            { name: 'deployment_comments', type: 'string', isOptional: true },
            { name: 'camera_location_description', type: 'string', isOptional: true },
            { name: 'camera_location_image_path', type: 'string', isOptional: true },
            { name: 'deployment_photos', type: 'string', isOptional: true } // JSON
        ];

        missingFields.forEach(field => {
            if (!existingNames.has(field.name)) {
                tables.deployments.push(field);
            }
        });

        // Override types for timestamps that come as string from Supabase but are number in Model (@date)
        const timestampFields = ['deployment_start', 'deployment_end'];
        tables.deployments = tables.deployments.map(col => {
            if (timestampFields.includes(col.name)) {
                return { ...col, type: 'number' };
            }
            return col;
        });
    }

    // 4. Generate Output (with auto-incrementing version)
    let currentVersion = 1;
    if (fs.existsSync(OUTPUT_SCHEMA_PATH)) {
        const existingContent = fs.readFileSync(OUTPUT_SCHEMA_PATH, 'utf8');
        const versionMatch = existingContent.match(/version:\s*(\d+)/);
        if (versionMatch && versionMatch[1]) {
            currentVersion = parseInt(versionMatch[1], 10) + 1;
            console.log(`ℹ️  Incrementing schema version to: ${currentVersion}`);
        } else {
            console.log('⚠️  Could not parse existing schema version, resetting to 1');
        }
    } else {
        console.log('ℹ️  No existing schema found, starting at version 1');
    }

    let output = SCHEMA_HEADER.replace('version: 1, // INCREMENT_VERSION_HERE', `version: ${currentVersion},`)
        .replace(/version:\s*\d+/, `version: ${currentVersion}`);

    Object.keys(tables).sort().forEach(tableName => {
        output += `        tableSchema({\n`;
        output += `            name: '${tableName}',\n`;
        output += `            columns: [\n`;

        // Standard Columns
        tables[tableName].forEach(col => {
            const props = [`name: '${col.name}'`, `type: '${col.type}'`];
            if (col.isOptional) props.push('isOptional: true');
            if (col.isIndexed) props.push('isIndexed: true');

            output += `                { ${props.join(', ')} },\n`;
        });

        // Sync/System Columns
        // Note: sync_state is a local-only table that doesn't follow standard sync patterns
        // so we exclude standard sync fields (except updated_at which is in the model)
        if (tableName !== 'sync_state') {
            output += `                // System & Sync Fields\n`;
            SYNC_FIELDS.forEach(field => {
                const props = [`name: '${field.name}'`, `type: '${field.type}'`];
                if (field.isOptional) props.push('isOptional: true');
                output += `                { ${props.join(', ')} },\n`;
            });
        } else {
            // Minimal fields for sync_state (only what's in the Model)
            output += `                { name: 'updated_at', type: 'number' },\n`;
        }

        output += `            ],\n`;
        output += `        }),\n`;
    });

    output += SCHEMA_FOOTER;

    fs.writeFileSync(OUTPUT_SCHEMA_PATH, output);
    console.log(`✅ Schema generated at: ${OUTPUT_SCHEMA_PATH}`);
}

generateSchema();
